const pricing = {
  "gemma4:31b":     { promptPrice: 0.000001, completionPrice: 0.000002 },
  "qwen3.5:latest": { promptPrice: 0.000001, completionPrice: 0.000002 },
  // add more models here
};

const body = $input.first().json.body;
const model = body.model || 'unknown';
const promptTokens = body.promptTokens || 0;
const completionTokens = body.completionTokens || 0;
const totalTokens = body.totalTokens || 0;

const modelPricing = pricing[model] || { promptPrice: 0, completionPrice: 0 };
const cost = (promptTokens * modelPricing.promptPrice) + (completionTokens * modelPricing.completionPrice);

return [{
  json: {
    workflowName: body.workflowName || 'unknown',
    model,
    promptTokens,
    completionTokens,
    totalTokens,
    cost: parseFloat(cost.toFixed(8))
  }
}];

